// MARK: - Network Service

class NetworkService: NSObject {
    static let shared = NetworkService()
    
    private var productionSession: URLSession!
    private var legacySession: URLSession!
    
    private override init() {
        super.init()
        
        // Production session with strict SSL
        let productionConfig = URLSessionConfiguration.default
        productionConfig.timeoutIntervalForRequest = 30
        productionConfig.timeoutIntervalForResource = 60
        productionConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        productionSession = URLSession(configuration: productionConfig, delegate: self, delegateQueue: nil)
        
        // Legacy session with relaxed security for internal systems
        let legacyConfig = URLSessionConfiguration.default
        legacyConfig.timeoutIntervalForRequest = 60
        legacyConfig.timeoutIntervalForResource = 120
        legacyConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        legacySession = URLSession(configuration: legacyConfig, delegate: self, delegateQueue: nil)
    }
    
    private func session(for environment: APIEnvironment) -> URLSession {
        switch environment {
        case .production:
            return productionSession
        case .legacy:
            return legacySession
        }
    }
    
    // MARK: - Generic Request Method
    
    func request<T: Codable>(
        environment: APIEnvironment,
        path: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        let urlString = "\(environment.baseURL)\(path)"
        
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let urlSession = session(for: environment)
        
        let task = urlSession.dataTask(with: request) { data, response, error in
            if let error = error {
                DispatchQueue.main.async {
                    completion(.failure(.networkError(error)))
                }
                return
            }
            
            if let httpResponse = response as? HTTPURLResponse {
                switch httpResponse.statusCode {
                case 200...299:
                    break
                case 401:
                    DispatchQueue.main.async {
                        completion(.failure(.unauthorized))
                    }
                    return
                case 500...599:
                    DispatchQueue.main.async {
                        completion(.failure(.serverError))
                    }
                    return
                default:
                    DispatchQueue.main.async {
                        completion(.failure(.httpError(statusCode: httpResponse.statusCode, data: data)))
                    }
                    return
                }
            }
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(.noData))
                }
                return
            }
            
            do {
                let decoded = try JSONDecoder().decode(T.self, from: data)
                DispatchQueue.main.async {
                    completion(.success(decoded))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.decodingError(error)))
                }
            }
        }
        
        task.resume()
    }
}

// MARK: - URLSessionDelegate for SSL Handling

extension NetworkService: URLSessionDelegate {
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        let host = challenge.protectionSpace.host
        
        if host.contains("api.example.com") {
            // For production: use default SSL validation
            if let serverTrust = challenge.protectionSpace.serverTrust {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.performDefaultHandling, nil)
            }
        } else if host.contains("legacy.internal") {
            // For legacy internal systems: accept self-signed certificates
            if let serverTrust = challenge.protectionSpace.serverTrust {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.performDefaultHandling, nil)
            }
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

// MARK: - API Client for Production Server

class ProductionAPIClient {
    private let networkService = NetworkService.shared
    private var authToken: String?
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    private var authHeaders: [String: String]? {
        guard let token = authToken else { return nil }
        return ["Authorization": "Bearer \(token)"]
    }
    
    func fetchUsers(completion: @escaping (Result<APIResponse<[APIUser]>, NetworkError>) -> Void) {
        networkService.request(
            environment: .production,
            path: "/v1/users",
            headers: authHeaders,
            completion: completion
        )
    }
    
    func fetchUser(id: Int, completion: @escaping (Result<APIResponse<APIUser>, NetworkError>) -> Void) {
        networkService.request(
            environment: .production,
            path: "/v1/users/\(id)",
            headers: authHeaders,
            completion: completion
        )
    }
    
    func createUser(name: String, email: String, completion: @escaping (Result<APIResponse<APIUser>, NetworkError>) -> Void) {
        let body: [String: Any] = ["name": name, "email": email]
        let bodyData = try? JSONSerialization.data(withJSONObject: body)
        
        networkService.request(
            environment: .production,
            path: "/v1/users",
            method: "POST",
            body: bodyData,
            headers: authHeaders,
            completion: completion
        )
    }
    
    func deleteUser(id: Int, completion: @escaping (Result<APIResponse<Bool>, NetworkError>) -> Void) {
        networkService.request(
            environment: .production,
            path: "/v1/users/\(id)",
            method: "DELETE",
            headers: authHeaders,
            completion: completion
        )
    }
}

// MARK: - API Client for Legacy System

class LegacyAPIClient {
    private let networkService = NetworkService.shared
    private var basicAuthCredentials: String?
    
    func setCredentials(username: String, password: String) {
        let credentials = "\(username):\(password)"
        basicAuthCredentials = Data(credentials.utf8).base64EncodedString()
    }
    
    private var authHeaders: [String: String]? {
        guard let credentials = basicAuthCredentials else { return nil }
        return ["Authorization": "Basic \(credentials)"]
    }
    
    func fetchRecords(completion: @escaping (Result<[LegacyRecord], NetworkError>) -> Void) {
        networkService.request(
            environment: .legacy,
            path: "/api/records",
            headers: authHeaders,
            completion: completion
        )
    }
    
    func fetchRecord(id: String, completion: @escaping (Result<LegacyRecord, NetworkError>) -> Void) {
        networkService.request(
            environment: .legacy,
            path: "/api/records/\(id)",
            headers: authHeaders,
            completion: completion
        )
    }
    
    func updateRecord(id: String, data: String, completion: @escaping (Result<LegacyRecord, NetworkError>) -> Void) {
        let body: [String: Any] = ["data": data]
        let bodyData = try? JSONSerialization.data(withJSONObject: body)
        
        networkService.request(
            environment: .legacy,
            path: "/api/records/\(id)",
            method: "PUT",
            body: bodyData,
            headers: authHeaders,
            completion: completion
        )
    }
    
    func syncData(completion: @escaping (Result<APIResponse<String>, NetworkError>) -> Void) {
        networkService.request(
