            path: "/api/sync",
            method: "POST",
            headers: authHeaders,
            completion: completion
        )
    }
}

// MARK: - Connection Status Checker

class ConnectionChecker {
    static func checkProductionServer(completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "\(APIEnvironment.production.baseURL)/health") else {
            completion(false)
            return
        }
        
        var request = URLRequest(url: url)
        request.timeoutInterval = 10
        request.httpMethod = "HEAD"
        
        URLSession.shared.dataTask(with: request) { _, response, error in
            let isReachable = error == nil && (response as? HTTPURLResponse)?.statusCode == 200
            DispatchQueue.main.async {
                completion(isReachable)
            }
        }.resume()
    }
    
    static func checkLegacyServer(completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "\(APIEnvironment.legacy.baseURL)/api/ping") else {
            completion(false)
            return
        }
        
        var request = URLRequest(url: url)
        request.timeoutInterval = 15
        request.httpMethod = "HEAD"
        
        URLSession.shared.dataTask(with: request) { _, response, error in
            let isReachable = error == nil && (response as? HTTPURLResponse)?.statusCode == 200
            DispatchQueue.main.async {
                completion(isReachable)
            }
        }.resume()
    }
}

