                if let users = response.data {
                    text += "Users (\(users.count)):\n"
                    for user in users {
                        text += "  - \(user.name) (\(user.email))\n"
                    }
                }
                if let message = response.message {
                    text += "Message: \(message)\n"
                }
                self?.displayResult(text)
            case .failure(let error):
