// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let navigationController = UINavigationController(rootViewController: ViewController())
        navigationController.navigationBar.prefersLargeTitles = true
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        logATSConfiguration()
        
        return true
    }
    
    private func logATSConfiguration() {
        print("=== App Transport Security Configuration ===")
        print("Production API: https://api.example.com (TLS 1.2+, Forward Secrecy)")
        print("Legacy System:  http://legacy.internal (HTTP allowed via ATS exception)")
        print("============================================")
        
        if let atsDict = Bundle.main.infoDictionary?["NSAppTransportSecurity"] as? [String: Any] {
            print("ATS Settings: \(atsDict)")
            if let exceptions = atsDict["NSExceptionDomains"] as? [String: Any] {
                for (domain, settings) in exceptions {
                    print("  Domain: \(domain)")
                    print("  Settings: \(settings)")
                }
            }
        }
    }
}